SELECT a.track_id, a.track_nm, a.album_id, f.artist_id repArtistId, f.artist_nm repArtistNm, a.agency_id, if(a.streaming_premium_yn = 'Y' OR a.pps_yn = 'Y', 'Y', 'N') holdbackYn, a.create_dtime, a.update_dtime, d.artist_id, d.artist_nm, b.album_img_size size, b.album_img_url url FROM tb_track a LEFT OUTER JOIN tb_album_img b ON a.album_id = b.album_id LEFT OUTER JOIN ted_trackartist as c ON a.track_id = c.track_id AND c.rp_yn = 'Y' LEFT OUTER JOIN ted_artist d ON c.artist_id = d.artist_id INNER JOIN ted_album e ON a.album_id = e.album_id AND e.disp_status_yn = 'Y' AND now() BETWEEN e.disp_start_dtime AND e.disp_end_dtime LEFT OUTER JOIN ted_artist f ON a.reprsnt_artist_id = f.artist_id WHERE a.track_id IN
#{trackId}
AND a.disp_status_yn = 'Y' AND now() BETWEEN a.disp_start_dtime AND a.disp_end_dtime ORDER BY FIELD ( a.track_id,
#{trackId}
)

